-- Stage 7 load (idempotent on slug/card_id). Generated by load.py.
-- Loads cards.json from GitHub server-side, so commit + push it first.
create extension if not exists http with schema extensions;
with j as (
  select (extensions.http_get('https://raw.githubusercontent.com/rjkmrdesai/card-gyani/main/scraper/out/cards.json')).content::jsonb as data
),
src as (
  select x.* from j, jsonb_to_recordset(j.data) as x(card_id text, bank text, name text, network text, network_confidence text, category text, type text, annual_fee numeric, joining_fee numeric, fee_waiver text, forex numeric, finance_pm numeric, finance_pa numeric, cash_advance text, cash_interest text, late_fee text, rewards text, lounge text, welcome_benefit text, features jsonb, badge text, apply_url text, source_url text, source_section text, match_status text, mitc_last_checked date, data_status text)
),
del as (
  delete from public.cards where slug in ('hdfc-moneyback-moneyback-business-moneyback','hdfc-regalia-first-business-regalia-first','hdfc-regalia-regalia-activ-business-regalia-diners-club-premium-doctor-s-regalia') returning 1
),
up as (
  insert into public.cards (card_id, slug, bank_name, card_name, network, network_confidence, category, card_type, annual_fee, joining_fee, fee_waiver, forex_markup_pct, finance_charge_monthly_pct, finance_charge_annual_pct, cash_advance_fee, cash_interest, late_payment_fee, reward_summary, lounge_access, welcome_benefit, features, badge, apply_url, source_url, source_section, match_status, mitc_last_checked, data_status, is_lifetime_free, updated_at)
  select card_id, card_id, bank, coalesce(name, card_id), network, network_confidence, category, type, annual_fee, joining_fee, fee_waiver, forex, finance_pm, finance_pa, cash_advance, cash_interest, late_fee, rewards, lounge, welcome_benefit, case when features is null then null else array(select jsonb_array_elements_text(features)) end, badge, apply_url, source_url, source_section, match_status, mitc_last_checked, data_status, (coalesce(annual_fee,0)=0 and coalesce(joining_fee,0)=0), now() from src
  on conflict (slug) do update set
    bank_name=excluded.bank_name, card_name=excluded.card_name, network=excluded.network, network_confidence=excluded.network_confidence, category=excluded.category, card_type=excluded.card_type, annual_fee=excluded.annual_fee, joining_fee=excluded.joining_fee, fee_waiver=excluded.fee_waiver, forex_markup_pct=excluded.forex_markup_pct, finance_charge_monthly_pct=excluded.finance_charge_monthly_pct, finance_charge_annual_pct=excluded.finance_charge_annual_pct, cash_advance_fee=excluded.cash_advance_fee, cash_interest=excluded.cash_interest, late_payment_fee=excluded.late_payment_fee, reward_summary=excluded.reward_summary, lounge_access=excluded.lounge_access, welcome_benefit=excluded.welcome_benefit, features=excluded.features, badge=excluded.badge, apply_url=excluded.apply_url, source_url=excluded.source_url, source_section=excluded.source_section, match_status=excluded.match_status, mitc_last_checked=excluded.mitc_last_checked, data_status=excluded.data_status, is_lifetime_free=excluded.is_lifetime_free, updated_at=excluded.updated_at
  returning (xmax = 0) as inserted
)
select (select count(*) from del) as deleted_orphans,
       count(*) filter (where inserted) as inserted,
       count(*) filter (where not inserted) as updated
from up;
